import React, { useEffect, useState } from "react";
import { BrowserRouter as Router, Routes, Route } from "react-router-dom";
import SignIn from "./pages/SignIn";
import Feed from "./pages/Feed";
import Chat from "./pages/Chat";
import Profile from "./pages/Profile";
import Notifications from "./pages/Notifications";
import OnboardingWizard from "./components/OnboardingWizard";

function App() {
  const [user, setUser] = useState<any>(null);
  const [needsOnboarding, setNeedsOnboarding] = useState(false);

  useEffect(() => {
    // Aqui você ajusta como valida se o usuário está logado
    const loggedUser = localStorage.getItem("user");
    setUser(loggedUser);

    // Verifica se precisa fazer onboarding
    const onboardingComplete = localStorage.getItem("onboardingComplete") === "true";
    setNeedsOnboarding(!onboardingComplete);
  }, []);

  // 🔒 Se não está logado → vai para SignIn
  if (!user) {
    return (
      <SignIn
        onGoogle={() => {
          console.log("Login com Google");
          localStorage.setItem("user", "googleUser");
          setUser("googleUser");
        }}
        onApple={() => {
          console.log("Login com Apple");
          localStorage.setItem("user", "appleUser");
          setUser("appleUser");
        }}
      />
    );
  }

  // 🎯 Se precisa de onboarding → abre Onboarding
  if (needsOnboarding) {
    return (
      <OnboardingWizard
        onDone={() => {
          localStorage.setItem("onboardingComplete", "true");
          setNeedsOnboarding(false);
        }}
      />
    );
  }

  // ✅ Se já logou e fez onboarding → libera as rotas principais
  return (
    <Router>
      <Routes>
        <Route path="/feed" element={<Feed />} />
        <Route path="/profile" element={<Profile />} />
        <Route path="/chat" element={<Chat />} />
        <Route path="/notifications" element={<Notifications />} />
        <Route path="*" element={<Feed />} /> {/* fallback */}
      </Routes>
    </Router>
  );
}

export default App;
