import React from "react";
import "./MultiStepForm.css";

interface MultiStepFormProps {
  step: number;
  setStep: (step: number) => void;
  onFinish: () => void;
}

const MultiStepForm: React.FC<MultiStepFormProps> = ({ step, setStep, onFinish }) => {
  const handleNext = () => {
    if (step < 3) {
      setStep(step + 1);
    } else {
      onFinish(); // Finaliza o onboarding
    }
  };

  const handleBack = () => {
    if (step > 1) {
      setStep(step - 1);
    }
  };

  return (
    <div className="form-container">
      <h2 className="form-title">Bem-vindo 🎓</h2>

      <div className="steps-indicator">
        {[1, 2, 3].map((s) => (
          <span key={s} className={`step-circle ${s === step ? "active" : ""}`}>
            {s}
          </span>
        ))}
      </div>

      {step === 1 && (
        <div className="form-step">
          <label>Data de nascimento</label>
          <input type="date" />
        </div>
      )}

      {step === 2 && (
        <div className="form-step">
          <label>Escolha sua universidade</label>
          <select>
            <option>Universidade de Lisboa</option>
            <option>Universidade do Porto</option>
            <option>Universidade de Coimbra</option>
          </select>
        </div>
      )}

      {step === 3 && (
        <div className="form-step">
          <label>Curso</label>
          <input type="text" placeholder="Digite seu curso" />
        </div>
      )}

      <div className="form-actions">
        {step > 1 && (
          <button className="btn-back" onClick={handleBack}>
            Voltar
          </button>
        )}
        <button className="btn-next" onClick={handleNext}>
          {step < 3 ? "Próximo" : "Concluir"}
        </button>
      </div>
    </div>
  );
};

export default MultiStepForm;
