import React from "react";

const msgs = [
  { id: 1, me: false, text: "Ah?" },
  { id: 2, me: false, text: "Legal" },
  { id: 3, me: false, text: "Como funciona?" },
  { id: 4, me: true,  text: "Basta editar o texto e enviar. :)" },
  { id: 5, me: false, text: "Hmmmm" },
  { id: 6, me: false, text: "Acho que entendi" },
  { id: 7, me: false, text: "Depois vejo a Central de Ajuda." },
];

export default function Chat() {
  return (
    <div className="card chat">
      <header className="chat-head">
        <img className="avatar" src="https://i.pravatar.cc/64?img=55" alt="" />
        <div>
          <strong>Ana Pintão</strong>
          <div className="muted">Online há 11 min</div>
        </div>
      </header>

      <div className="chat-body">
        {msgs.map((m) => (
          <div key={m.id} className={m.me ? "bubble me" : "bubble"}>
            {m.text}
          </div>
        ))}
      </div>

      <footer className="chat-input">
        <input placeholder="Mensagem…" />
        <button className="btn">Enviar</button>
      </footer>
    </div>
  );
}
