import React from "react";

const items = [
  { id: 1, name: "anaPintao", when: "1d", text: "Começou a seguir você", avatar: "https://i.pravatar.cc/52?img=14", thumb: "" },
  { id: 2, name: "nebulanomad", when: "1d", text: "Curtiu seu post", avatar: "https://i.pravatar.cc/52?img=22", thumb: "https://picsum.photos/seed/1/56/56" },
  { id: 3, name: "emberecho", when: "2d", text: "Curtiu seu comentário — Seja bem vinda!!! 🎉", avatar: "https://i.pravatar.cc/52?img=31", thumb: "" },
  { id: 4, name: "lunavoyager", when: "3d", text: "Salvou seu post", avatar: "https://i.pravatar.cc/52?img=41", thumb: "https://picsum.photos/seed/2/56/56" },
  { id: 5, name: "shadowlynx", when: "4d", text: "Comentou no seu post — Vou em setembro. E você?", avatar: "https://i.pravatar.cc/52?img=47", thumb: "" },
];

export default function Notifications() {
  return (
    <div className="card">
      <h3 className="title">Notificações</h3>
      <ul className="notifs">
        {items.map((n) => (
          <li key={n.id} className="notif">
            <span className="dot" />
            <img className="avatar" src={n.avatar} alt="" />
            <div className="notif-body">
              <div className="notif-title"><strong>{n.name}</strong> <span className="muted">{n.when}</span></div>
              <div>{n.text}</div>
            </div>
            {n.thumb && <img className="thumb" src={n.thumb} alt="" />}
          </li>
        ))}
      </ul>
    </div>
  );
}
