import React from "react";
import "./SignIn.css";

interface SignInProps {
  onGoogle: () => void;
  onApple: () => void;
}

const SignIn: React.FC<SignInProps> = ({ onGoogle, onApple }) => {
  return (
    <div className="signin-container">
      <div className="signin-card">
        {/* Logo / Nome */}
        <h1 className="logo-text">VibeU ✨</h1>

        {/* Bem-vindo */}
        <h2 className="signin-title">Bem-vindo 👋</h2>
        <p className="signin-subtitle">
          Conecte-se com colegas do mundo todo
        </p>

        {/* Botões sociais */}
        <div className="signin-buttons">
          <button className="btn-social google" onClick={onGoogle}>
            <img
              src="/assets/google-icon.png"
              alt="Google"
              className="btn-icon"
            />
            Entrar com Google
          </button>

          <button className="btn-social apple" onClick={onApple}>
            <img
              src="/assets/apple-icon.png"
              alt="Apple"
              className="btn-icon"
            />
            Entrar com Apple
          </button>
        </div>
      </div>
    </div>
  );
};

export default SignIn;
